from flask import Flask, request, session, redirect, url_for
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your_secret_key'

def parse_saml_response(saml_response):
    root = ET.fromstring(saml_response)
    namespace = {'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
                 'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'}
    
    assertion_element = root.find('.//samlp:Assertion', namespaces=namespace)
    if not assertion_element:
        raise ValueError("No Assertion found in the SAML response")
    
    user_attributes = {}
    attributes_statement = assertion_element.find('.//saml:AttributeStatement', namespaces=namespace)
    for attr in attributes_statement.findall('.//saml:Attribute', namespaces=namespace):
        attribute_name = attr.get('Name')
        attribute_values = [value.text for value in attr.findall('.//saml:AttributeValue', namespaces=namespace)]
        user_attributes[attribute_name] = attribute_values
    
    return user_attributes

@app.route('/acs', methods=['POST'])
def acs():
    saml_response = request.form['SAMLResponse']
    
    try:
        user_attributes = parse_saml_response(saml_response)
        session['user'] = user_attributes
        return redirect(url_for('home'))
    except ValueError as e:
        return str(e), 400

@app.route('/home')
def home():
    if 'user' not in session:
        return redirect(url_for('acs'))
    
    user_info = session['user']
    return f"Welcome, {user_info.get('name', ['Unknown User'])[0]}!"

if __name__ == '__main__':
    app.run(debug=True)